function gcd(a, b) {
    a = Math.abs(a);
    b = Math.abs(b);
    if (b === 0) return a;
    return gcd(b, a % b);
}

function normalizeLine(a, b, c) {
    if (a === 0 && b === 0) {
        return [0, 0, 0];
    }
    let g = gcd(a, gcd(b, c));
    if (g === 0) {
        g = 1;
    }
    a = a / g;
    b = b / g;
    c = c / g;
    if (a < 0 || (a === 0 && b < 0)) {
        a = -a;
        b = -b;
        c = -c;
    }
    return [a, b, c];
}

function solve(points) {
