function isTrapezoid(a, b, c, d) {
    if (checkParallel(a, b, c, d)) return true;
    if (checkParallel(a, c, b, d)) return true;
    if (checkParallel(a, d, b, c)) return true;
    return false;
}

function checkParallel(pa, pb, pc, pd) {
    const dx1 = pb.x - pa.x;
    const dy1 = pb.y - pa.y;
    const dx2 = pd.x - pc.x;
    const dy2 = pd.y - pc.y;

    if (dx1 === 0 && dx2 === 0) {
        return true;
    } else if (dx1 === 0 || dx2 === 0) {
        return false;
    } else {
        return dy1 * dx2 === dy2 * dx1;
    }
}
